{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "type": "command",
            "command": "bash -c 'INPUT=$(cat); CMD=$(echo \"$INPUT\" | jq -r \".tool_input.command\"); if echo \"$CMD\" | grep -qE \"rm -rf|rm -f /|: > /|truncate -s 0\"; then echo \"Blocked: destructive command\" >&2; exit 2; fi'"
          }
        ]
      }
    ]
  }
}

{
  "mcpServers": {
    "my-local-tool": {
      "type": "stdio",
      "command": "node",
      "args": ["./mcp-server.js"],
      "env": {
        "LOG_LEVEL": "info"
      }
    }
  }
}

{
  "mcpServers": {
    "my-server": {
      "command": "npx",
      "args": ["-y", "@my-org/mcp-server", "--config", "/path/to/config"],
      "env": {
        "API_KEY": "your-key-here"
      }
    }
  }
}

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";

const server = new McpServer({
  name: "my-server",
  version: "1.0.0",
});

server.registerTool(
  "my_tool",
  {
    description: "Execute a query.",
    inputSchema: { query: z.string() },
  },
  async ({ query }) => ({
    content: [{ type: "text", text: `Result for: ${query}` }],
  })
);

const transport = new StdioServerTransport();
await server.connect(transport);

{
  "name": "Manual → HTTP → Set",
  "nodes": [
    {
      "parameters": {},
      "type": "n8n-nodes-base.manualTrigger",
      "typeVersion": 1,
      "position": [0, 0],
      "id": "00000000-0000-0000-0000-000000000001",
      "name": "When clicking 'Execute workflow'"
    },
    {
      "parameters": {
        "url": "https://api.example.com/v1/status",
        "options": {}
      },
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4.2,
      "position": [260, 0],
      "id": "00000000-0000-0000-0000-000000000002",
      "name": "Fetch status"
    },
    {
      "parameters": {
        "assignments": {
          "assignments": [
            {
              "id": "11111111-1111-1111-1111-111111111111",
              "name": "isHealthy",
              "value": "={{ $json.status === 'ok' }}",
              "type": "boolean"
            }
          ]
        },
        "options": {}
      },
      "type": "n8n-nodes-base.set",
      "typeVersion": 3.4,
      "position": [520, 0],
      "id": "00000000-0000-0000-0000-000000000003",
      "name": "Extract isHealthy"
    }
  ],
  "connections": {
    "When clicking 'Execute workflow'": {
      "main": [[{ "node": "Fetch status", "type": "main", "index": 0 }]]
    },
    "Fetch status": {
      "main": [[{ "node": "Extract isHealthy", "type": "main", "index": 0 }]]
    }
  },
  "pinData": {},
  "settings": { "executionOrder": "v1" },
  "active": false
}

{
  "name": "Webhook → HTTP → Respond",
  "nodes": [
    {
      "parameters": {
        "httpMethod": "POST",
        "path": "my-proxy",
        "responseMode": "responseNode",
        "options": {}
      },
      "type": "n8n-nodes-base.webhook",
      "typeVersion": 2,
      "position": [0, 0],
      "id": "00000000-0000-0000-0000-00000000000a",
      "name": "Webhook",
      "webhookId": "00000000-0000-0000-0000-00000000000w"
    },
    {
      "parameters": {
        "method": "POST",
        "url": "https://upstream.example.com/v1/ingest",
        "sendBody": true,
        "bodyParameters": {
          "parameters": [
            { "name": "payload", "value": "={{ $json.body }}" }
          ]
        },
        "options": {}
      },
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4.2,
      "position": [260, 0],
      "id": "00000000-0000-0000-0000-00000000000b",
      "name": "Forward to upstream"
    },
    {
      "parameters": {
        "respondWith": "allIncomingItems",
        "options": {}
      },
      "type": "n8n-nodes-base.respondToWebhook",
      "typeVersion": 1.1,
      "position": [520, 0],
      "id": "00000000-0000-0000-0000-00000000000c",
      "name": "Respond"
    }
  ],
  "connections": {
    "Webhook": {
      "main": [[{ "node": "Forward to upstream", "type": "main", "index": 0 }]]
    },
    "Forward to upstream": {
      "main": [[{ "node": "Respond", "type": "main", "index": 0 }]]
    }
  },
  "pinData": {},
  "settings": { "executionOrder": "v1" },
  "active": false
}

{
  "name": "Schedule → HTTP → Set",
  "nodes": [
    {
      "parameters": {
        "rule": {
          "interval": [
            { "field": "hours", "hoursInterval": 6 }
          ]
        }
      },
      "type": "n8n-nodes-base.scheduleTrigger",
      "typeVersion": 1.2,
      "position": [0, 0],
      "id": "00000000-0000-0000-0000-000000000010",
      "name": "Every 6 hours"
    },
    {
      "parameters": {
        "url": "https://api.example.com/v1/metrics",
        "options": {}
      },
      "type": "n8n-nodes-base.httpRequest",
      "typeVersion": 4.2,
      "position": [260, 0],
      "id": "00000000-0000-0000-0000-000000000011",
      "name": "Fetch metrics"
    },
    {
      "parameters": {
        "assignments": {
          "assignments": [
            {
              "id": "22222222-2222-2222-2222-222222222222",
              "name": "activeUsers",
              "value": "={{ $json.metrics.activeUsers }}",
              "type": "number"
            },
            {
              "id": "33333333-3333-3333-3333-333333333333",
              "name": "fetchedAt",
              "value": "={{ $now.toISO() }}",
              "type": "string"
            }
          ]
        },
        "options": {}
      },
      "type": "n8n-nodes-base.set",
      "typeVersion": 3.4,
      "position": [520, 0],
      "id": "00000000-0000-0000-0000-000000000012",
      "name": "Extract metrics"
    }
  ],
  "connections": {
    "Every 6 hours": {
      "main": [[{ "node": "Fetch metrics", "type": "main", "index": 0 }]]
    },
    "Fetch metrics": {
      "main": [[{ "node": "Extract metrics", "type": "main", "index": 0 }]]
    }
  },
  "pinData": {},
  "settings": { "executionOrder": "v1" },
  "active": false
}
